ACK https://github.com/bitcoin/bitcoin/pull/34988/commits/a09d7913114c1e3345e12e38cf1bc2b0ddc72c8c

Should probably do the same for `decodepsbt_outputs`.


Note for other reviewers: much smaller diff whitespace changes [hidden](https://github.com/bitcoin/bitcoin/pull/34988/changes/a09d7913114c1e3345e12e38cf1bc2b0ddc72c8c?w=1):

<details>
<summary>

```bash
git show a09d791 -b
```

</summary>

```diff
diff --git a/src/rpc/rawtransaction.cpp b/src/rpc/rawtransaction.cpp
index 2a1a4d1a06..b226f055ef 100644
--- a/src/rpc/rawtransaction.cpp
+++ b/src/rpc/rawtransaction.cpp
@@ -775,7 +775,9 @@ static RPCMethod signrawtransactionwithkey()
     };
 }

-const RPCResult decodepsbt_inputs{
+const RPCResult& DecodePSBTInputs()
+{
+    static const RPCResult decodepsbt_inputs{
         RPCResult::Type::ARR, "inputs", "",
         {
             {RPCResult::Type::OBJ, "", "",
@@ -930,7 +932,9 @@ const RPCResult decodepsbt_inputs{
                 }},
             }},
         }
-};
+    };
+    return decodepsbt_inputs;
+}

 const RPCResult decodepsbt_outputs{
     RPCResult::Type::ARR, "outputs", "",
@@ -1048,7 +1052,7 @@ static RPCMethod decodepsbt()
                         {
                              {RPCResult::Type::STR_HEX, "key", "(key-value pair) An unknown key-value pair"},
                         }},
-                        decodepsbt_inputs,
+                        DecodePSBTInputs(),
                         decodepsbt_outputs,
                         {RPCResult::Type::STR_AMOUNT, "fee", /*optional=*/true, "The transaction fee paid if all UTXOs slots in the PSBT have been filled."},
                     }
```

</details>
